import jsPDF from 'jspdf';

/**
 * Identidad de marca compartida para TODAS las impresiones PDF del POS.
 * Garantiza tipografía uniforme (font size + font weight), membrete con el
 * logo Muebles Castro en la esquina superior derecha y un bloque de firmas
 * que asegura que toda impresión ocupe más de la mitad de la página.
 */

/** Logo Muebles Castro a color, fondo transparente (para el membrete). */
const LOGO_DATA_URL =
  'data:image/png;base64,';

/** Relación ancho/alto nativa del logo (340x275). */
const LOGO_RATIO = 340 / 275;

/** Leyenda de marca usada en el membrete de toda impresión. */
export const BRAND_LEGEND = 'Ventas, diseño y fabricación de muebles';

export interface PdfFont {
  size: number;
  weight: 'bold' | 'normal';
}

/**
 * Escala tipográfica ÚNICA. Los tres servicios de impresión usan estos
 * valores para que toda hoja impresa tenga el mismo font size y font weight
 * por rol de texto.
 */
export const TYPO: Record<
  'title' | 'subtitle' | 'heading' | 'section' | 'tableHead' | 'body' | 'total' | 'note',
  PdfFont
> = {
  title:     { size: 16, weight: 'bold'   },
  subtitle:  { size: 11, weight: 'normal' },
  heading:   { size: 13, weight: 'bold'   },
  section:   { size: 11, weight: 'bold'   },
  tableHead: { size:  9, weight: 'bold'   },
  body:      { size: 10, weight: 'normal' },
  total:     { size: 12, weight: 'bold'   },
  note:      { size:  9, weight: 'normal' },
};

/** Paleta de marca para PDFs (terracota + grises). */
export const PDF_COLOR: {
  terracotta: [number, number, number];
  ink: number;
  gray: number;
  muted: number;
  faint: number;
} = {
  terracotta: [200, 90, 26],
  ink: 50,
  gray: 100,
  muted: 140,
  faint: 160,
};

/** Aplica un rol tipográfico de la escala compartida. */
export function setType(doc: jsPDF, font: PdfFont): void {
  doc.setFontSize(font.size);
  doc.setFont('helvetica', font.weight);
}

export interface LetterheadOptions {
  storeName: string;
  docTitle: string;
  /** Líneas de meta (nº de comprobante, estado, fecha…) bajo el título. */
  metaLines: string[];
}

const LOGO_W = 30; // mm — ancho del membrete

/**
 * Dibuja el membrete en la página actual: encabezado de texto a la izquierda
 * y el logo a color en la esquina superior derecha, cerrado por una regla
 * terracota. Devuelve la `y` (mm) donde debe continuar el contenido.
 */
export function drawLetterhead(doc: jsPDF, opts: LetterheadOptions): number {
  const pW = doc.internal.pageSize.getWidth();
  const m = 14;
  const topY = 14;
  const logoH = LOGO_W / LOGO_RATIO;

  // Logo — esquina superior derecha.
  doc.addImage(LOGO_DATA_URL, 'PNG', pW - m - LOGO_W, topY, LOGO_W, logoH);

  // Texto del membrete — alineado a la izquierda.
  let y = topY + 6;
  setType(doc, TYPO.title);
  doc.setTextColor(...PDF_COLOR.terracotta);
  doc.text(opts.storeName, m, y);
  y += 7;
  setType(doc, TYPO.subtitle);
  doc.setTextColor(PDF_COLOR.gray);
  doc.text(BRAND_LEGEND, m, y);
  y += 6;
  setType(doc, TYPO.heading);
  doc.setTextColor(PDF_COLOR.ink);
  doc.text(opts.docTitle, m, y);
  y += 6;
  setType(doc, TYPO.body);
  doc.setTextColor(80);
  for (const line of opts.metaLines) {
    doc.text(line, m, y);
    y += 5;
  }

  // Regla terracota bajo el bloque más alto (texto o logo).
  const ruleY = Math.max(y, topY + logoH + 2) + 1;
  doc.setDrawColor(...PDF_COLOR.terracotta);
  doc.setLineWidth(0.6);
  doc.line(m, ruleY, pW - m, ruleY);
  doc.setLineWidth(0.2);
  return ruleY + 6;
}

/**
 * Logo reducido en la esquina superior derecha para páginas de continuación.
 * Devuelve la `y` donde continuar el contenido.
 */
export function drawContinuationMark(doc: jsPDF): number {
  const pW = doc.internal.pageSize.getWidth();
  const m = 14;
  const w = 20;
  const h = w / LOGO_RATIO;
  doc.addImage(LOGO_DATA_URL, 'PNG', pW - m - w, m, w, h);
  return m + h + 4;
}

/**
 * Bloque de firmas (Cliente / Vendedor) anclado en la mitad inferior de la
 * página. Garantiza que el contenido impreso pase de la mitad de la hoja.
 * Llamar justo antes del footer.
 */
export function drawSignatures(doc: jsPDF, currentY: number): void {
  const pW = doc.internal.pageSize.getWidth();
  const pH = doc.internal.pageSize.getHeight();
  const m = 14;
  const usableW = pW - 2 * m;
  const sigW = 64;

  const footerTop = pH - 22;
  let y = Math.max(currentY + 10, pH * 0.55);
  if (y > footerTop - 16) y = footerTop - 16;

  const lineY = y + 10;
  const leftX = m + usableW * 0.25 - sigW / 2;
  const rightX = m + usableW * 0.75 - sigW / 2;

  doc.setDrawColor(120);
  doc.line(leftX, lineY, leftX + sigW, lineY);
  doc.line(rightX, lineY, rightX + sigW, lineY);

  setType(doc, TYPO.note);
  doc.setTextColor(PDF_COLOR.gray);
  doc.text('Cliente', leftX + sigW / 2, lineY + 5, { align: 'center' });
  doc.text('Vendedor', rightX + sigW / 2, lineY + 5, { align: 'center' });
}
